module RefModule (
    input wire D,
    input wire E,
    output reg Q
);
  wire _tap_D = D & {1{1'b1}};

    always @ (D or E) begin
        if (E) begin
            Q <= D;  // Capture input D if enable E is high
        end
        // If E is low, Q retains its previous state
    end
endmodule
